sys_script_include.script:
var FMXPCalculator = Class.create();
FMXPCalculator.prototype = {
    initialize: function() {},

    /**
     * Awards XP to a user profile, creates an XP log record, and updates their total XP.
     * @param {string} userProfileSysId - sys_id of the user profile
     * @param {number} xpAmount - amount of XP to award
     * @param {string} sourceType - type of source (e.g., 'task_completion', 'achievement', 'streak_bonus')
     * @param {string} sourceTaskSysId - sys_id of the source task (can be empty)
     * @param {string} description - description of the XP award
     */
    awardXP: function(userProfileSysId, xpAmount, sourceType, sourceTaskSysId, description) {
        // Create XP log record
        var xpLog = new GlideRecord('x_2063628_flowmi_0_fm_xp_log');
        xpLog.initialize();
        xpLog.setValue('user_profile', userProfileSysId);
        xpLog.setValue('xp_amount', xpAmount);
        xpLog.setValue('source_type', sourceType);
        if (sourceTaskSysId) {
            xpLog.setValue('source_task', sourceTaskSysId);
        }
        xpLog.setValue('description', description);
        xpLog.setValue('awarded_date', new GlideDateTime().toString());
        xpLog.insert();

        // Update user profile total_xp
        var profile = new GlideRecord('x_2063628_flowmi_0_fm_user_profile');
        if (profile.get(userProfileSysId)) {
            var currentXP = parseInt(profile.getValue('total_xp')) || 0;
            var newTotalXP = currentXP + xpAmount;
            profile.setValue('total_xp', newTotalXP);
            profile.update();

            // Update user level after XP change
            this.updateUserLevel(userProfileSysId);
        }
    },

    /**
     * Calculates the level number based on total XP.
     * Levels 1-10: 100 XP per level (0-1000)
     * Levels 11-20: 200 XP per level (1000-3000)
     * Levels 21+: 500 XP per level (3000+)
     * @param {number} totalXP - total XP amount
     * @returns {number} level number
     */
    calculateLevelFromXP: function(totalXP) {
        if (totalXP <= 0) {
            return 1;
        }

        // Levels 1-10: 100 XP per level (0-1000 XP)
        if (totalXP <= 1000) {
            return Math.floor(totalXP / 100) + 1;
        }

        // Levels 11-20: 200 XP per level (1000-3000 XP)
        var remainingAfterLevel10 = totalXP - 1000;
        if (remainingAfterLevel10 <= 2000) {
            return 10 + Math.floor(remainingAfterLevel10 / 200) + 1;
        }

        // Levels 21+: 500 XP per level (3000+ XP)
        var remainingAfterLevel20 = totalXP - 3000;
        return 20 + Math.floor(remainingAfterLevel20 / 500) + 1;
    },

    /**
     * Recalculates and updates a user's current_level based on their total_xp.
     * @param {string} userProfileSysId - sys_id of the user profile
     */
    updateUserLevel: function(userProfileSysId) {
        var profile = new GlideRecord('x_2063628_flowmi_0_fm_user_profile');
        if (profile.get(userProfileSysId)) {
            var totalXP = parseInt(profile.getValue('total_xp')) || 0;
            var newLevel = this.calculateLevelFromXP(totalXP);
            profile.setValue('current_level', newLevel);
            profile.update();
        }
    },

    /**
     * Returns XP multiplier based on task priority.
     * @param {string} priority - task priority value
     * @returns {number} XP multiplier
     */
    getXPForPriority: function(priority) {
        switch (String(priority)) {
            case 'critical':
                return 2.0;
            case 'high':
                return 1.5;
            case 'medium':
                return 1.0;
            case 'low':
                return 0.5;
            default:
                return 1.0;
        }
    },

    type: 'FMXPCalculator'
};
